178	//-------------------------------------------------------------------------------------------------
179	/*static*/ void PlayerTemplate::parseStartMoney( INI* ini, void *instance, void *store, const void* /*userData*/ )
180	{
181		Int money = 0;
182	
183		// parse the money as a regular "FIELD = <integer>"
184		INI::parseInt( ini, instance, &money, NULL );
185	
186		// assign the money into the 'Money' (m_money) pointed to at 'store'
187		Money *theMoney = (Money *)store;
188		theMoney->init();
189		theMoney->deposit( money );
190	
191	}  // end parseStartMoney
