766				UnsignedInt silly = GetGameLogicRandomSeed() % 7;
767				for (Int poo = 0; poo < silly; ++poo) 
768				{
769					GameLogicRandomValue(0, 1);	// ignore result
770				}
771				Int idxIdx = GameLogicRandomValue(0, 1000) % startSlots.size();
772				playerTemplateIdx = startSlots[idxIdx];
773	#else
774				playerTemplateIdx = GameLogicRandomValue(0, ThePlayerTemplateStore->getPlayerTemplateCount()-1);
775	#endif
776				const PlayerTemplate* pt = ThePlayerTemplateStore->getNthPlayerTemplate(playerTemplateIdx);
777				if (!pt || pt->getStartingBuilding().isEmpty())
778				{
779	#ifdef MORE_RANDOM
780					DEBUG_CRASH(("should not be possible"));
781	#endif
782					playerTemplateIdx = -1; // only pick playable factions
783				}
784				else
785				{
786					DEBUG_LOG(("Setting playerTemplateIdx %d to %d\n", i, playerTemplateIdx));
787					slot->setPlayerTemplate(playerTemplateIdx);
788				}
789			}
790	
791			Int colorIdx = slot->getColor();
792			if (colorIdx < 0 || colorIdx >= TheMultiplayerSettings->getNumColors())
793			{
794				DEBUG_ASSERTCRASH(colorIdx == -1, ("Non-random bad color %d in slot %d\n", colorIdx, i));
795				while (colorIdx == -1)
796				{
797					colorIdx = GameLogicRandomValue(0, TheMultiplayerSettings->getNumColors()-1);
798					if (game->isColorTaken(colorIdx))
799						colorIdx = -1;
800				}
801				DEBUG_LOG(("Setting color %d to %d\n", i, colorIdx));
802				slot->setColor(colorIdx);
803			}
804		}
